// lib/market-terminal/promptBuilder.js
// Specularis Market Terminal Lite — AI Prompt Export Builder.
// Generates a copyable prompt for GPT Plus / Claude Pro (no API calls made here).

/**
 * Build a comprehensive analysis prompt from current snapshot state.
 *
 * @param {object} params
 *   marketRegime       - current regime object
 *   stockIntelligence  - array of stock intel entries
 *   optionsLite        - array of options lite entries
 *   kolDistillation    - array of KOL entries
 *   aiDecisionLayer    - array of scored decisions
 *   lang               - "zh" | "en"
 * @returns {string} copyable prompt text
 */
export function buildAnalysisPrompt({
  marketRegime = {},
  stockIntelligence = [],
  optionsLite = [],
  kolDistillation = [],
  aiDecisionLayer = [],
  lang = "zh",
}) {
  const now = new Date().toLocaleString("zh-CN", {
    timeZone: "America/New_York",
    hour12: false,
  });

  const regimeStr = marketRegime.label || marketRegime.mode || "未知";
  const regimeScore = marketRegime.score ?? "--";

  const topDecisions = [...aiDecisionLayer]
    .filter((d) => d.score !== null && d.rating !== "placeholder")
    .sort((a, b) => (b.score || 0) - (a.score || 0))
    .slice(0, 5);

  const stockSummaryLines = stockIntelligence.map((s) => {
    const price = s.currentPrice ? `$${s.currentPrice}` : "N/A";
    const change = s.dailyChangePercent != null ? `${s.dailyChangePercent}%` : "N/A";
    const news = s.recentNews?.slice(0, 1)[0] || "无最新新闻";
    return `  - ${s.ticker} (${s.companyName}): 价格 ${price}, 涨跌 ${change}, 趋势 ${s.trendStatus || "N/A"}, 分析师 ${s.analystTone || "N/A"}, 新闻: ${typeof news === "object" ? news.title || "无" : news}`;
  });

  const optionsSummaryLines = optionsLite.map((o) => {
    return `  - ${o.ticker}: 期权建议 ${o.preferredStructure}, IV ${o.ivStatus || "N/A"}, 财报风险 ${o.earningsVolRisk ? "是" : "否"}, 风险等级 ${o.riskLevel}`;
  });

  const kolLines =
    kolDistillation.length > 0
      ? kolDistillation.slice(0, 5).map((k) => {
          const tickers = k.mentionedTickers?.join(", ") || "无";
          return `  - @${k.kolHandle}: 立场 ${k.stance}, 信号 ${k.signalType}, 置信 ${k.convictionLevel}, 涉及 ${tickers}`;
        })
      : ["  - 暂无 KOL 输入。"];

  const decisionLines =
    topDecisions.length > 0
      ? topDecisions.map(
          (d) =>
            `  - ${d.ticker}: 评分 ${d.score}/10, 评级 ${d.rating}, 动作 ${d.action}, 工具 ${d.preferredVehicle}, 进场区间 ${d.keyEntryZone || "N/A"}, 止损 ${d.invalidationLevel || "N/A"}`
        )
      : ["  - 暂无有效决策评分。（数据质量不足）"];

  const disclaimerZh =
    "\n\n⚠️ 以上数据由 Specularis Market Terminal Lite 生成，部分字段可能为占位符。仅供研究，不构成投资建议。";
  const disclaimerEn =
    "\n\n⚠️ Data generated by Specularis Market Terminal Lite. Some fields may be placeholders. For research only, not financial advice.";

  if (lang === "en") {
    return `
=== SPECULARIS MARKET TERMINAL LITE — AI ANALYSIS PROMPT ===
Generated: ${now} EST

## CURRENT MARKET REGIME
Status: ${regimeStr} | Score: ${regimeScore}/100

## WATCHLIST STOCK INTELLIGENCE
${stockSummaryLines.join("\n") || "  - No data available."}

## OPTIONS INTELLIGENCE LITE
${optionsSummaryLines.join("\n") || "  - No data available."}

## KOL DISTILLATION
${kolLines.join("\n")}

## AI DECISION LAYER (Top Scores)
${decisionLines.join("\n")}

## ANALYSIS REQUESTS
Please analyze the above data and provide:
1. What is the current market regime and how does it affect AI/semiconductor stocks?
2. Which 3 tickers from the watchlist (MU, MRVL, NVDA, AVGO, AMD, TSM, ASML, PLTR, ORCL, SMCI) are most tradable today?
3. For each top ticker: is stock or option participation preferred? Is IV/event risk too high?
4. What is your A+ score (0-10) for the top opportunity? Provide entry, stop, and target zones.
5. Are there any no-trade conditions I should respect today?
6. Summarize the top risk factors to watch.

Respond in structured format. Keep recommendations conservative when data quality is mixed.
${disclaimerEn}
`.trim();
  }

  return `
=== SPECULARIS 市场终端 LITE — AI 分析提示词 ===
生成时间：${now} 美东时间

## 当前市场状态
状态：${regimeStr} | 评分：${regimeScore}/100

## 个股情报 Pro（观察池）
${stockSummaryLines.join("\n") || "  - 暂无数据。"}

## 期权情报 Lite
${optionsSummaryLines.join("\n") || "  - 暂无数据。"}

## KOL 观点蒸馏
${kolLines.join("\n")}

## AI 决策层（评分排行）
${decisionLines.join("\n")}

## 分析请求
请根据以上数据回答：
1. 当前市场状态对 AI / 半导体板块意味着什么？
2. 观察池（MU、MRVL、NVDA、AVGO、AMD、TSM、ASML、PLTR、ORCL、SMCI）中哪 3 个标的今日最具交易性？
3. 对于每个顶级标的：建议做股票还是期权？当前 IV / 财报风险是否过高？
4. 最强机会的 A+ 评分（0-10 分）是多少？请给出进场区间、止损位和目标位。
5. 今日有无必须遵守的不可交易条件？
6. 总结最需要关注的风险因素。

请以结构化格式回答。数据质量混合时，建议保守处理。
${disclaimerZh}
`.trim();
}

/**
 * Build a quick pre-market brief prompt (shorter version).
 */
export function buildPremarketPrompt({
  marketRegime = {},
  topDecisions = [],
  lang = "zh",
}) {
  const regimeStr = marketRegime.label || marketRegime.mode || "未知";
  const tickers = topDecisions
    .slice(0, 3)
    .map((d) => `${d.ticker}(${d.rating || "?"})`)
    .join(", ") || "NVDA, MRVL, PLTR";

  if (lang === "en") {
    return `Market regime: ${regimeStr}. Top candidates: ${tickers}. Please provide pre-market trade plan with entry, stop, and target for each. Note any IV or earnings risk. For research only.`;
  }
  return `当前市场：${regimeStr}。顶级标的：${tickers}。请为每个标的提供盘前交易计划（进场、止损、目标），并标注 IV 或财报风险。仅供研究。`;
}
